1722 /// Determine whether an individual user of the narrow IV can be widened. If so,
1723 /// return the wide clone of the user.
1724 Instruction *WidenIV::widenIVUse(WidenIV::NarrowIVDefUse DU, SCEVExpander &Rewriter) {
1725   assert(ExtendKindMap.count(DU.NarrowDef) &&
1726          "Should already know the kind of extension used to widen NarrowDef");
1727 
1728   // Stop traversing the def-use chain at inner-loop phis or post-loop phis.
1729   if (PHINode *UsePhi = dyn_cast<PHINode>(DU.NarrowUse)) {
1730     if (LI->getLoopFor(UsePhi->getParent()) != L) {
1731       // For LCSSA phis, sink the truncate outside the loop.
1732       // After SimplifyCFG most loop exit targets have a single predecessor.
1733       // Otherwise fall back to a truncate within the loop.
1734       if (UsePhi->getNumOperands() != 1)
1735         truncateIVUse(DU, DT, LI);
1736       else {
1737         // Widening the PHI requires us to insert a trunc.  The logical place
1738         // for this trunc is in the same BB as the PHI.  This is not possible if
1739         // the BB is terminated by a catchswitch.
1740         if (isa<CatchSwitchInst>(UsePhi->getParent()->getTerminator()))
1741           return nullptr;
1742 
1743         PHINode *WidePhi =
1744           PHINode::Create(DU.WideDef->getType(), 1, UsePhi->getName() + ".wide",
1745                           UsePhi);
1746         WidePhi->addIncoming(DU.WideDef, UsePhi->getIncomingBlock(0));
1747         BasicBlock *WidePhiBB = WidePhi->getParent();
1748         IRBuilder<> Builder(WidePhiBB, WidePhiBB->getFirstInsertionPt());
1749         Value *Trunc = Builder.CreateTrunc(WidePhi, DU.NarrowDef->getType());
1750         UsePhi->replaceAllUsesWith(Trunc);
1751         DeadInsts.emplace_back(UsePhi);
1752         LLVM_DEBUG(dbgs() << "INDVARS: Widen lcssa phi " << *UsePhi << " to "
1753                           << *WidePhi << "\n");
1754       }
1755       return nullptr;
1756     }
1757   }
1758 
1759   // This narrow use can be widened by a sext if it's non-negative or its narrow
1760   // def was widended by a sext. Same for zext.
1761   auto canWidenBySExt = [&]() {
1762     return DU.NeverNegative || getExtendKind(DU.NarrowDef) == ExtendKind::Sign;
1763   };
1764   auto canWidenByZExt = [&]() {
1765     return DU.NeverNegative || getExtendKind(DU.NarrowDef) == ExtendKind::Zero;
1766   };
