1874 /// Add eligible users of NarrowDef to NarrowIVUsers.
1875 void WidenIV::pushNarrowIVUsers(Instruction *NarrowDef, Instruction *WideDef) {
1876   const SCEV *NarrowSCEV = SE->getSCEV(NarrowDef);
1877   bool NonNegativeDef =
1878       SE->isKnownPredicate(ICmpInst::ICMP_SGE, NarrowSCEV,
1879                            SE->getZero(NarrowSCEV->getType()));
1880   for (User *U : NarrowDef->users()) {
1881     Instruction *NarrowUser = cast<Instruction>(U);
1882 
1883     // Handle data flow merges and bizarre phi cycles.
1884     if (!Widened.insert(NarrowUser).second)
1885       continue;
1886 
1887     bool NonNegativeUse = false;
1888     if (!NonNegativeDef) {
1889       // We might have a control-dependent range information for this context.
1890       if (auto RangeInfo = getPostIncRangeInfo(NarrowDef, NarrowUser))
1891         NonNegativeUse = RangeInfo->getSignedMin().isNonNegative();
1892     }
1893 
1894     NarrowIVUsers.emplace_back(NarrowDef, NarrowUser, WideDef,
1895                                NonNegativeDef || NonNegativeUse);
1896   }
1897 }
