2093 /// Calculates PostIncRangeInfos map for the given IV
2094 void WidenIV::calculatePostIncRanges(PHINode *OrigPhi) {
2095   SmallPtrSet<Instruction *, 16> Visited;
2096   SmallVector<Instruction *, 6> Worklist;
2097   Worklist.push_back(OrigPhi);
2098   Visited.insert(OrigPhi);
2099 
2100   while (!Worklist.empty()) {
2101     Instruction *NarrowDef = Worklist.pop_back_val();
2102 
2103     for (Use &U : NarrowDef->uses()) {
2104       auto *NarrowUser = cast<Instruction>(U.getUser());
2105 
2106       // Don't go looking outside the current loop.
2107       auto *NarrowUserLoop = (*LI)[NarrowUser->getParent()];
2108       if (!NarrowUserLoop || !L->contains(NarrowUserLoop))
2109         continue;
2110 
2111       if (!Visited.insert(NarrowUser).second)
2112         continue;
2113 
2114       Worklist.push_back(NarrowUser);
2115 
2116       calculatePostIncRange(NarrowDef, NarrowUser);
2117     }
2118   }
2119 }
