1680     User->replaceAllUsesWith(WideBO);
1681     DeadInsts.emplace_back(User);
1682   }
1683 
1684   for (PHINode *User : LCSSAPhiUsers) {
1685     assert(User->getNumOperands() == 1 && "Checked before!");
